CREATE INDEX "archivemodel_repo_id" ON "archivemodel" ("repo_id");
CREATE INDEX "backupprofilemodel_repo_id" ON "backupprofilemodel" ("repo_id");
CREATE INDEX "exclusionmodel_profile_id" ON "exclusionmodel" ("profile_id");
CREATE INDEX "sourcefilemodel_profile_id" ON "sourcedirmodel" ("profile_id");
CREATE INDEX "wifisettingmodel_profile_id" ON "wifisettingmodel" ("profile_id");
CREATE TABLE IF NOT EXISTS "archivemodel" ("id" INTEGER NOT NULL PRIMARY KEY, "snapshot_id" VARCHAR(255) NOT NULL, "name" VARCHAR(255) NOT NULL, "repo_id" INTEGER NOT NULL, "time" DATETIME NOT NULL, "duration" REAL, "size" INTEGER, "trigger" VARCHAR(255), FOREIGN KEY ("repo_id") REFERENCES "repomodel" ("id"));
CREATE TABLE IF NOT EXISTS "backupprofilemodel" ("id" INTEGER NOT NULL PRIMARY KEY, "name" VARCHAR(255) NOT NULL, "added_at" DATETIME NOT NULL, "repo_id" INTEGER, "ssh_key" VARCHAR(255), "compression" VARCHAR(255) NOT NULL, "exclude_patterns" TEXT, "exclude_if_present" TEXT, "schedule_mode" VARCHAR(255) NOT NULL, "schedule_interval_count" INTEGER NOT NULL, "schedule_interval_unit" VARCHAR(255) NOT NULL, "schedule_fixed_hour" INTEGER NOT NULL, "schedule_fixed_minute" INTEGER NOT NULL, "schedule_interval_hours" INTEGER NOT NULL, "schedule_interval_minutes" INTEGER NOT NULL, "schedule_make_up_missed" INTEGER NOT NULL, "validation_on" INTEGER NOT NULL, "validation_weeks" INTEGER NOT NULL, "prune_on" INTEGER NOT NULL, "prune_hour" INTEGER NOT NULL, "prune_day" INTEGER NOT NULL, "prune_week" INTEGER NOT NULL, "prune_month" INTEGER NOT NULL, "prune_year" INTEGER NOT NULL, "prune_keep_within" VARCHAR(255), "new_archive_name" VARCHAR(255) NOT NULL, "prune_prefix" VARCHAR(255) NOT NULL, "pre_backup_cmd" VARCHAR(255) NOT NULL, "post_backup_cmd" VARCHAR(255) NOT NULL, "dont_run_on_metered_networks" INTEGER NOT NULL, "compaction_on" INTEGER NOT NULL, "compaction_weeks" INTEGER NOT NULL, FOREIGN KEY ("repo_id") REFERENCES "repomodel" ("id"));
CREATE TABLE IF NOT EXISTS "eventlogmodel" ("id" INTEGER NOT NULL PRIMARY KEY, "start_time" DATETIME NOT NULL, "end_time" DATETIME NOT NULL, "category" VARCHAR(255) NOT NULL, "subcommand" VARCHAR(255), "message" VARCHAR(255), "returncode" INTEGER NOT NULL, "params" TEXT, "profile" VARCHAR(255), "repo_url" VARCHAR(255));
CREATE TABLE IF NOT EXISTS "exclusionmodel" ("id" INTEGER NOT NULL PRIMARY KEY, "profile_id" INTEGER NOT NULL, "name" VARCHAR(255) NOT NULL, "enabled" INTEGER NOT NULL, "source" VARCHAR(255) NOT NULL, FOREIGN KEY ("profile_id") REFERENCES "backupprofilemodel" ("id"));
CREATE TABLE IF NOT EXISTS "repomodel" ("id" INTEGER NOT NULL PRIMARY KEY, "url" VARCHAR(255) NOT NULL, "added_at" DATETIME NOT NULL, "encryption" VARCHAR(255), "unique_size" INTEGER, "unique_csize" INTEGER, "total_size" INTEGER, "total_unique_chunks" INTEGER, "create_backup_cmd" VARCHAR(255) NOT NULL, "extra_borg_arguments" VARCHAR(255) NOT NULL, "name" VARCHAR(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "repopassword" ("id" INTEGER NOT NULL PRIMARY KEY, "url" VARCHAR(255) NOT NULL, "password" VARCHAR(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "schemaversion" ("id" INTEGER NOT NULL PRIMARY KEY, "version" INTEGER NOT NULL, "changed_at" DATETIME NOT NULL);
CREATE TABLE IF NOT EXISTS "settingsmodel" ("id" INTEGER NOT NULL PRIMARY KEY, "key" VARCHAR(255) NOT NULL, "value" INTEGER NOT NULL, "str_value" VARCHAR(255) NOT NULL, "label" VARCHAR(255) NOT NULL, "group" VARCHAR(255) NOT NULL, "tooltip" VARCHAR(255) NOT NULL, "type" VARCHAR(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "sourcedirmodel" ("id" INTEGER NOT NULL PRIMARY KEY, "dir" VARCHAR(255) NOT NULL, "dir_size" INTEGER NOT NULL, "dir_files_count" INTEGER NOT NULL, "path_isdir" INTEGER NOT NULL, "profile_id" INTEGER NOT NULL, "added_at" DATETIME NOT NULL, FOREIGN KEY ("profile_id") REFERENCES "backupprofilemodel" ("id"));
CREATE TABLE IF NOT EXISTS "wifisettingmodel" ("id" INTEGER NOT NULL PRIMARY KEY, "ssid" VARCHAR(255) NOT NULL, "last_connected" DATETIME, "allowed" INTEGER NOT NULL, "profile_id" INTEGER NOT NULL, FOREIGN KEY ("profile_id") REFERENCES "backupprofilemodel" ("id"));
CREATE UNIQUE INDEX "repomodel_url" ON "repomodel" ("url");
CREATE UNIQUE INDEX "repopassword_url" ON "repopassword" ("url");
CREATE UNIQUE INDEX "settingsmodel_key" ON "settingsmodel" ("key");
